mapper.update:
MERGE  STOCMTGC MTGC
USING (SELECT #{ses.gateCd}  AS GATE_CD
             ,#{ses.manageCd} AS BUYER_CD
             ,#{ITEM_CD} AS ITEM_CD
             ,(CASE WHEN SF_SUBSTR(#{ITEM_CLS1},1,1) = 'P' THEN '0' ELSE '1' END) AS M_CATE_YN
             ,(CASE WHEN SF_SUBSTR(#{ITEM_CLS1},1,1) = 'P' THEN '1' ELSE '0' END) AS P_CATE_YN from dual
      ) T
ON (MTGC.GATE_CD = T.GATE_CD
 AND MTGC.BUYER_CD = T.BUYER_CD
 AND MTGC.ITEM_CD = T.ITEM_CD
 AND MTGC.M_CATE_YN = T.M_CATE_YN
 AND MTGC.P_CATE_YN = T.P_CATE_YN)

WHEN MATCHED THEN UPDATE SET
      MOD_DATE = SYSDATE
     ,MOD_USER_ID = #{ses.userId}
     ,ITEM_CLS1 = #{ITEM_CLS1}
     ,ITEM_CLS2 = #{ITEM_CLS2}
     ,ITEM_CLS3 = #{ITEM_CLS3}
     ,ITEM_CLS4 = #{ITEM_CLS4}
WHEN NOT MATCHED THEN INSERT (
     GATE_CD
    ,BUYER_CD
    ,ITEM_CD
    ,M_CATE_YN
    ,P_CATE_YN
    ,ITEM_CLS1
    ,ITEM_CLS2
    ,ITEM_CLS3
    ,ITEM_CLS4
    ,REG_DATE
    ,REG_USER_ID
    ,MOD_DATE
    ,MOD_USER_ID
    ,DEL_FLAG
) VALUES (
     #{ses.gateCd}
    ,#{ses.manageCd}
    ,#{ITEM_CD}
    ,'1'
    ,'0'
    ,#{ITEM_CLS1}
    ,#{ITEM_CLS2}
    ,#{ITEM_CLS3}
    ,#{ITEM_CLS4}
    ,SYSDATE
    ,#{ses.userId}
    ,SYSDATE
    ,#{ses.userId}
    ,'0'
)

mapper.select:
		SELECT MTCR.GATE_CD
             , MTCR.BUYER_CD
       		 , MTCR.ITEM_CLS1
       		 ,(SELECT ITEM_CLS_NM FROM STOCMTCA
       		    WHERE GATE_CD   = MTCR.GATE_CD
       		      AND BUYER_CD  = MTCR.BUYER_CD
       		      AND ITEM_CLS_TYPE = 'C1'
       		      AND ITEM_CLS1 = #{ITEM_CLS1}
       		      AND DEL_FLAG  = '0') AS ITEM_CLS1_NM
       		 , MTCR.ITEM_CLS2
       		 ,(SELECT ITEM_CLS_NM FROM STOCMTCA
       		    WHERE GATE_CD   = MTCR.GATE_CD
       		      AND BUYER_CD  = MTCR.BUYER_CD
       		      AND ITEM_CLS_TYPE = 'C2'
       		      AND ITEM_CLS1 = #{ITEM_CLS1}
       		      AND ITEM_CLS2 = #{ITEM_CLS2}
       		      AND DEL_FLAG  = '0') AS ITEM_CLS2_NM
       		 , MTCR.ITEM_CLS3
       		 ,(SELECT ITEM_CLS_NM FROM STOCMTCA
       		    WHERE GATE_CD   = MTCR.GATE_CD
       		      AND BUYER_CD  = MTCR.BUYER_CD
       		      AND ITEM_CLS_TYPE = 'C3'
       		      AND ITEM_CLS1 = #{ITEM_CLS1}
       		      AND ITEM_CLS2 = #{ITEM_CLS2}
       		      AND ITEM_CLS3 = #{ITEM_CLS3}
       		      AND DEL_FLAG  = '0') AS ITEM_CLS3_NM
       		 , MTCR.ITEM_CLS4
       		 ,(SELECT ITEM_CLS_NM FROM STOCMTCA
       		    WHERE GATE_CD   = MTCR.GATE_CD
       		      AND BUYER_CD  = MTCR.BUYER_CD
       		      AND ITEM_CLS_TYPE = 'C4'
       		      AND ITEM_CLS1 = #{ITEM_CLS1}
       		      AND ITEM_CLS2 = #{ITEM_CLS2}
       		      AND ITEM_CLS3 = #{ITEM_CLS3}
       		      AND ITEM_CLS4 = #{ITEM_CLS4}
       		      AND DEL_FLAG  = '0') AS ITEM_CLS4_NM
       		 , MTCR.ATTR_CD AS CODE
			 , MTCR.ATTR_CD
       		 , MTCR.ATTR_NM AS CODE_NM
       		 , MTCR.MDT_FLAG
       		 , (MTCR.SORT_SQ, 1) AS SORT_SQ
       		 , MTCR.ATTR_RMK
       		 , 'U' AS INSERT_FLAG
       	  FROM STOCMTCR MTCR
         WHERE MTCR.GATE_CD   = #{ses.gateCd}
           AND MTCR.BUYER_CD  = #{ses.manageCd}
    	   AND MTCR.ITEM_CLS1 = #{ITEM_CLS1}
    	   AND MTCR.ITEM_CLS2 = #{ITEM_CLS2}
    	   AND MTCR.ITEM_CLS3 = #{ITEM_CLS3}
    	   AND MTCR.ITEM_CLS4 = #{ITEM_CLS4}
       	   AND MTCR.DEL_FLAG  = '0'
    	 ORDER BY MTCR.SORT_SQ

SELECT MKBR.MKBR_TYPE , MKBR.MKBR_CD , MKBR.MKBR_NM , MKBR.USE_FLAG , MKBR.MAJOR_ITEM_TEXT , MKBR.ADD_TEXT , MKBR.REG_USER_ID AS REG_USER_ID , getUserName(#{ses.gateCd}, MKBR.REG_USER_ID, #{ses.langCd}) AS REG_USER_NM , getUserName(#{ses.gateCd}, MKBR.MOD_USER_ID, #{ses.langCd}) AS MOD_USER_NM , ( MKBR.REG_DATE , 'YYYY-MM-DD HH24:MI') AS REG_DATE , ( MKBR.MOD_DATE , 'YYYY-MM-DD HH24:MI') AS MOD_DATE , MKBR.MOD_USER_ID FROM STOCMKBR MKBR WHERE MKBR.GATE_CD = #{ses.gateCd} AND MKBR.BUYER_CD = #{ses.manageCd}
AND MKBR.MKBR_TYPE = #{MKBR_TYPE}
AND UPPER(MKBR.MKBR_NM) LIKE '%'UPPER(#{MKBR_NM})'%'
AND MKBR.USE_FLAG = #{USE_FLAG}
AND MKBR.DEL_FLAG = '0' ORDER BY MKBR.MKBR_TYPE DESC, MKBR.MKBR_CD

mapper.update:
MERGE  STOCMKBR MKBR
USING (SELECT #{ses.gateCd} AS GATE_CD
			 ,#{ses.manageCd} AS BUYER_CD
             ,#{MKBR_TYPE} AS MKBR_TYPE
             ,#{MKBR_CD} AS MKBR_CD
) DATA
ON (MKBR.GATE_CD = DATA.GATE_CD
AND MKBR.BUYER_CD = DATA.BUYER_CD
AND MKBR.MKBR_TYPE = DATA.MKBR_TYPE
AND MKBR.MKBR_CD = DATA.MKBR_CD)

WHEN MATCHED THEN
UPDATE SET
     MKBR_NM = #{MKBR_NM}
    ,USE_FLAG = #{USE_FLAG}
    ,MAJOR_ITEM_TEXT = #{MAJOR_ITEM_TEXT}
    ,ADD_TEXT = #{ADD_TEXT}
    ,MOD_DATE = SYSDATE
    ,MOD_USER_ID = #{ses.userId}
WHEN NOT MATCHED THEN
INSERT (
     GATE_CD
    ,BUYER_CD
    ,MKBR_TYPE
    ,MKBR_CD
    ,REG_DATE
    ,REG_USER_ID
    ,MOD_DATE
    ,MOD_USER_ID
    ,DEL_FLAG
    ,MKBR_NM
    ,USE_FLAG
    ,MAJOR_ITEM_TEXT
    ,ADD_TEXT
) VALUES (
    #{ses.gateCd}
    ,#{ses.manageCd}
    ,#{MKBR_TYPE}
    ,(SELECT #{MKBR_TYPE}SF_LPAD((MAX(SF_SUBSTR(MK.MKBR_CD, 3, 5)), 0) + 1, 4, '0') FROM STOCMKBR MK WHERE MK.GATE_CD = #{ses.gateCd} AND MK.BUYER_CD = #{ses.manageCd} AND MK.MKBR_TYPE = #{MKBR_TYPE})
    ,SYSDATE
    ,#{ses.userId}
    ,SYSDATE
    ,#{ses.userId}
    ,'0'
    ,#{MKBR_NM}
    ,#{USE_FLAG}
    ,#{MAJOR_ITEM_TEXT}
    ,#{ADD_TEXT}
)

